code = """import json
import re

# Read the file paths from the storage variables
papers_pa_path = 'var_functions.query_db:2'
print(f"Loading papers from: {papers_pa_path}")

# Load the data
try:
    with open(papers_pa_path, 'r') as f:
        papers_pa = json.load(f)
    print(f"Successfully loaded {len(papers_pa)} papers")
except Exception as e:
    print(f"Error loading file: {e}")
    papers_pa = []

# Extract year from text
def extract_year_from_text(text):
    # Look for year patterns
    patterns = [
        r'\b(2016)\b',  # Explicit 2016
        r'CHI\s*[\'']?\s*16',  # CHI '16 or CHI 16
        r'UbiComp\s*[\'']?\s*16',
        r'CSCW\s*[\'']?\s*16',
        r'\b(20\d{2})\b'  # Any 20xx year
    ]
    
    for pattern in patterns:
        match = re.search(pattern, text)
        if match:
            year_str = match.group(1) if match.groups() else match.group(0)
            if '16' in year_str and len(year_str) <= 4:
                return 2016
            elif year_str.isdigit():
                year = int(year_str)
                if 2010 <= year <= 2020:
                    return year
    return None

# Process papers
papers_2016_info = []

for paper in papers_pa:
    year = extract_year_from_text(paper['text'][:2000])  # Check first 2000 chars
    if year == 2016:
        title = paper['filename'].replace('.txt', '')
        papers_2016_info.append({
            'title': title,
            'year': year
        })

print(f"\nFound {len(papers_2016_info)} papers from 2016 in physical activity domain:")
for p in papers_2016_info:
    print(f"- {p['title']}")

# Prepare result
result = json.dumps(papers_2016_info, indent=2)
print('__RESULT__:')
print(result)"""

